export const BP_MOBILE_MAX_PX = 640;
export const BP_TABLET_MAX_PX = 1024;

export const BREAKPOINTS = {
  mobile: BP_MOBILE_MAX_PX + 1,
  tablet: BP_TABLET_MAX_PX + 1,
} as const;

export const CONTENT_SIZE_SMALL_MAX = BREAKPOINTS.mobile;
export const CONTENT_SIZE_LARGE_MIN = BREAKPOINTS.tablet;

export const ERP_LINES_TABLE_MIN_WIDTH = 680;
export const ERP_HEADER_ROW4_MEDIUM_MAX_PX = 900;
export const ERP_HEADER_ROW4_SMALL_MAX_PX = 600;
export const TOUCH_LINES_STACK_NARROW_MAX_PX = 480;

export const VIEW_MOBILE_MEDIA_QUERY = '(hover: none) and (pointer: coarse)' as const;

export const MEDIA_QUERY = {
  viewportMobileMax: `(max-width: ${BP_MOBILE_MAX_PX}px)`,
  viewportTabletMax: `(max-width: ${BP_TABLET_MAX_PX}px)`,
  viewportTabletRange: `(min-width: ${BREAKPOINTS.mobile}px) and (max-width: ${BP_TABLET_MAX_PX}px)`,
  viewMobile: VIEW_MOBILE_MEDIA_QUERY,
  viewMobileLinesNarrow: `${VIEW_MOBILE_MEDIA_QUERY} and (max-width: ${TOUCH_LINES_STACK_NARROW_MAX_PX}px)`,
  erpHeaderRow4Medium: `(max-width: ${ERP_HEADER_ROW4_MEDIUM_MAX_PX}px)`,
  erpHeaderRow4Small: `(max-width: ${ERP_HEADER_ROW4_SMALL_MAX_PX}px)`,
} as const;

export const BREAKPOINT_CSS_VAR = {
  mobileMax: '--linm-bp-mobile-max',
  tabletMax: '--linm-bp-tablet-max',
  contentSmallMax: '--linm-content-size-small-max',
  contentLargeMin: '--linm-content-size-large-min',
  erpRow4MediumMax: '--linm-erp-row4-medium-max',
  erpRow4SmallMax: '--linm-erp-row4-small-max',
  linesTableMinWidth: '--linm-erp-lines-table-min-width',
  touchLinesNarrowMax: '--linm-touch-lines-narrow-max',
} as const;

export type DeviceContentSize = 'small' | 'medium' | 'large';

export function resolveDeviceContentSize(contentWidth: number): DeviceContentSize {
  if (contentWidth < CONTENT_SIZE_SMALL_MAX) return 'small';
  if (contentWidth < CONTENT_SIZE_LARGE_MIN) return 'medium';
  return 'large';
}

function parseSidebarWidthPx(): number {
  if (typeof document === 'undefined') return 0;
  const raw = getComputedStyle(document.documentElement).getPropertyValue('--sidebar-width').trim();
  if (!raw) return 0;
  const n = parseFloat(raw);
  return Number.isFinite(n) ? n : 0;
}

export function measureContentWidth(): number {
  if (typeof window === 'undefined') return CONTENT_SIZE_LARGE_MIN;
  const root =
    document.querySelector('[data-modal-root]') ??
    document.querySelector('[data-content-root]');
  if (root instanceof HTMLElement && root.clientWidth > 0) {
    return root.clientWidth;
  }
  return Math.max(0, window.innerWidth - parseSidebarWidthPx());
}

export function getDeviceContentSize(): DeviceContentSize {
  return resolveDeviceContentSize(measureContentWidth());
}

export function matchesViewMobileLayout(): boolean {
  if (typeof window === 'undefined') return false;
  return window.matchMedia(VIEW_MOBILE_MEDIA_QUERY).matches;
}
