import { useEffect, useRef } from 'react';
import type { Location, NavigateFunction } from 'react-router-dom';
import { FormMode } from '../form/FormMode';
import {
  VOUCHER_COPY_STATE_KEY,
  VOUCHER_SEARCH_CACHE_KEY,
  VOUCHER_SEARCH_RESULT_IDS_KEY,
} from './constants';

type CopyState<T> = { [VOUCHER_COPY_STATE_KEY]?: T };
type SearchNavState = {
  [VOUCHER_SEARCH_RESULT_IDS_KEY]?: string[];
  [VOUCHER_SEARCH_CACHE_KEY]?: unknown;
};

function stripVoucherSearchRouterState(state: unknown): Record<string, unknown> {
  if (!state || typeof state !== 'object') return {};
  const next = { ...(state as Record<string, unknown>) };
  delete next[VOUCHER_SEARCH_RESULT_IDS_KEY];
  delete next[VOUCHER_SEARCH_CACHE_KEY];
  return next;
}

export interface UseVoucherFormRouteOptions<TSnapshot> {
  isNew: boolean;
  id?: string;
  location: Location;
  navigate: NavigateFunction;
  setFormMode: (mode: FormMode) => void;
  setSearchResultIds: (ids: string[]) => void;
  resetEmptyForm: () => void;
  applyCopySnapshot: (snap: TSnapshot) => void;
  initNewSavedSnapshot: () => void;
  onRouteChange?: () => void;
}

/**
 * Đồng bộ FormMode khi đổi route + áp snapshot Copy trên `/them`.
 * Dùng chung mọi full-page voucher form trong ERP MFE.
 */
export function useVoucherFormRoute<TSnapshot>({
  isNew,
  id,
  location,
  navigate,
  setFormMode,
  setSearchResultIds,
  resetEmptyForm,
  applyCopySnapshot,
  initNewSavedSnapshot,
  onRouteChange,
}: UseVoucherFormRouteOptions<TSnapshot>): void {
  const initializedNewRef = useRef(false);
  const routeKeyRef = useRef(`${isNew}:${id ?? ''}`);
  const lastAppliedCopyKeyRef = useRef<string | null>(null);
  /** Đã strip `VOUCHER_SEARCH_RESULT_IDS_KEY` khỏi location.state — tránh replace mỗi next/prev. */
  const searchStateStrippedRef = useRef(false);

  const applyCopySnapshotRef = useRef(applyCopySnapshot);
  const initNewSavedSnapshotRef = useRef(initNewSavedSnapshot);
  applyCopySnapshotRef.current = applyCopySnapshot;
  initNewSavedSnapshotRef.current = initNewSavedSnapshot;

  useEffect(() => {
    const routeKey = `${isNew}:${id ?? ''}`;
    if (routeKeyRef.current === routeKey) return;
    routeKeyRef.current = routeKey;
    onRouteChange?.();

    if (isNew) {
      searchStateStrippedRef.current = false;
      setFormMode(FormMode.Create);
      setSearchResultIds([]);
      const copy = (location.state as CopyState<TSnapshot>)?.[VOUCHER_COPY_STATE_KEY];
      if (!copy) {
        resetEmptyForm();
        initializedNewRef.current = false;
        lastAppliedCopyKeyRef.current = null;
      }
    } else {
      setFormMode(FormMode.View);
      const searchIds = (location.state as SearchNavState)?.[VOUCHER_SEARCH_RESULT_IDS_KEY];
      if (Array.isArray(searchIds) && searchIds.length > 0) {
        setSearchResultIds(searchIds);
        if (!searchStateStrippedRef.current) {
          searchStateStrippedRef.current = true;
          navigate(
            { pathname: location.pathname, search: location.search },
            { replace: true, state: stripVoucherSearchRouterState(location.state) },
          );
        }
      }
    }
  }, [
    isNew,
    id,
    location.state,
    location.pathname,
    location.search,
    navigate,
    resetEmptyForm,
    setFormMode,
    setSearchResultIds,
    onRouteChange,
  ]);

  useEffect(() => {
    if (!isNew) {
      initializedNewRef.current = false;
      lastAppliedCopyKeyRef.current = null;
      return;
    }
    const copy = (location.state as CopyState<TSnapshot>)?.[VOUCHER_COPY_STATE_KEY];
    if (copy) {
      const copyKey = JSON.stringify(copy);
      if (copyKey === lastAppliedCopyKeyRef.current) return;
      lastAppliedCopyKeyRef.current = copyKey;
      applyCopySnapshotRef.current(copy);
      setFormMode(FormMode.Create);
      navigate(location.pathname, { replace: true, state: {} });
      initializedNewRef.current = true;
      return;
    }
    if (!initializedNewRef.current) {
      initializedNewRef.current = true;
      initNewSavedSnapshotRef.current();
    }
  }, [isNew, location.pathname, location.state, navigate, setFormMode]);
}

export function buildVoucherCopyNavigateState<TSnapshot>(snapshot: TSnapshot): CopyState<TSnapshot> {
  return { [VOUCHER_COPY_STATE_KEY]: snapshot };
}
