/**
 * Layout hooks — mirror of `@linm-soft/common-components` until next publish.
 * SSOT values: `src/layout/linmBreakpoints.ts`
 */
import { useEffect, useState } from 'react';
import {
  VIEW_MOBILE_MEDIA_QUERY,
  getDeviceContentSize,
  matchesViewMobileLayout,
  measureContentWidth,
  resolveDeviceContentSize,
  type DeviceContentSize,
} from './linmBreakpoints';

export {
  VIEW_MOBILE_MEDIA_QUERY,
  matchesViewMobileLayout,
  MEDIA_QUERY,
  BREAKPOINTS,
  BREAKPOINT_CSS_VAR,
  BP_MOBILE_MAX_PX,
  BP_TABLET_MAX_PX,
  CONTENT_SIZE_SMALL_MAX,
  CONTENT_SIZE_LARGE_MIN,
  ERP_LINES_TABLE_MIN_WIDTH,
  ERP_HEADER_ROW4_MEDIUM_MAX_PX,
  ERP_HEADER_ROW4_SMALL_MAX_PX,
  TOUCH_LINES_STACK_NARROW_MAX_PX,
  measureContentWidth,
  getDeviceContentSize,
  resolveDeviceContentSize,
} from './linmBreakpoints';

export type { DeviceContentSize };

export function useViewMobileLayout(): boolean {
  const [active, setActive] = useState(matchesViewMobileLayout);

  useEffect(() => {
    const mq = window.matchMedia(VIEW_MOBILE_MEDIA_QUERY);
    const sync = () => setActive(mq.matches);
    const timer = window.setTimeout(() => {
      mq.addEventListener('change', sync);
    }, 0);
    return () => {
      clearTimeout(timer);
      mq.removeEventListener('change', sync);
    };
  }, []);

  return active;
}

export interface DeviceContentSizeState {
  size: DeviceContentSize;
  contentWidth: number;
  isSmall: boolean;
  isMedium: boolean;
  isLarge: boolean;
}

function readDeviceContentState(): DeviceContentSizeState {
  const contentWidth = measureContentWidth();
  const size = resolveDeviceContentSize(contentWidth);
  return {
    size,
    contentWidth,
    isSmall: size === 'small',
    isMedium: size === 'medium',
    isLarge: size === 'large',
  };
}

export function useDeviceContentSize(): DeviceContentSizeState {
  const [state, setState] = useState<DeviceContentSizeState>(() => readDeviceContentState());

  useEffect(() => {
    const sync = () => setState(readDeviceContentState());
    const timer = window.setTimeout(() => {
      sync();
      window.addEventListener('resize', sync);
    }, 0);

    const observed =
      document.querySelector('[data-modal-root]') ??
      document.querySelector('[data-content-root]');

    let ro: ResizeObserver | undefined;
    if (observed instanceof HTMLElement && typeof ResizeObserver !== 'undefined') {
      ro = new ResizeObserver(sync);
      ro.observe(observed);
    }

    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', sync);
      ro?.disconnect();
    };
  }, []);

  return state;
}
